    "metrics": [
      "BFCL per-category accuracy and relevance suite, defined as the unweighted average of simple, multiple, parallel, and parallel_multiple for Non-Live.",
      "τ2-Bench per-domain pass rate and average across airline, retail, and telecom.",
      "Helpfulness: percentage of cases where the base agent is wrong and reviewer feedback corrects it.",
      "Harmfulness: percentage of cases where the base agent is right and reviewer feedback degrades it.",
      "Benefit-to-Risk Ratio: Helpfulness divided by Harmfulness.",
      "Latency metrics: mean, median, and P95 latency/duration for BFCL per item and τ2-Bench per episode."
    ],
    "baselines": [
      "Base tool-calling agent is GPT-4o, specifically gpt-4o-2024-11-20, temperature=0, seed=42.",
      "BFCL baseline: GPT-4o without reviewer, e.g., Non-Live 90.9 relevance suite and 84.9 irrelevance.",
      "τ2-Bench baseline: GPT-4o without reviewer, 42.0 airline, 62.9 retail, 41.2 telecom, 48.7 average.",
      "Reviewer/model configurations include GPT-4o, o3-mini, and GPT-5 mini; mechanisms include progressive feedback rN, best-of-N selection sN, and best-of-N grading gN."
